// Validate and normalize input
const input = $input.first().json;
const body = input.body || input;

// Required field check
if (!body.rawIdea || body.rawIdea.trim().length < 10) {
  throw new Error('rawIdea is required and must be at least 10 characters');
}

// Normalize and set defaults
const normalized = {
  ideaId: `IDEA-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
  title: body.title || 'Untitled Idea',
  rawIdea: body.rawIdea.trim(),
  diagramType: body.diagramType || 'auto',  // auto, flowchart, mindmap, timeline, comparison, process
  targetAudience: body.targetAudience || 'general',
  visualStyle: body.visualStyle || 'professional',  // professional, casual, minimal, bold
  outputFormats: body.outputFormats || ['png', 'svg'],
  projectTag: body.projectTag || 'general',
  priority: body.priority || 'normal',
  requestedAt: new Date().toISOString(),
  wordCount: body.rawIdea.trim().split(/\s+/).length
};

console.log(`✅ Validated idea: ${normalized.ideaId} - "${normalized.title}"`);

return [{ json: normalized }];

