// Parse Claude AI enrichment response
const claudeResponse = $input.first().json;
const ideaData = $node['Validate & Normalize Input'].first().json;

try {
  const rawText = claudeResponse.content?.[0]?.text || '';

  // Strip any accidental markdown fences
  const clean = rawText.replace(/```json|```/g, '').trim();
  const enrichment = JSON.parse(clean);

  return [{
    json: {
      // Original idea data
      ...ideaData,
      // AI enrichment
      enrichedText: enrichment.enrichedText,
      diagramType: enrichment.diagramType || ideaData.diagramType,
      napkinPrompt: enrichment.napkinPrompt,
      keyNodes: enrichment.keyNodes || [],
      relationships: enrichment.relationships || [],
      visualHierarchy: enrichment.visualHierarchy,
      colorScheme: enrichment.colorScheme,
      alternativeFormats: enrichment.alternativeFormats || [],
      contentAngles: enrichment.contentAngles || [],
      estimatedComplexity: enrichment.estimatedComplexity || 'moderate',
      recommendedDimensions: enrichment.recommendedDimensions || { width: 1200, height: 675, ratio: '16:9' },
      // Status tracking
      enrichedAt: new Date().toISOString(),
      stage: 'enriched'
    }
  }];

} catch (error) {
  console.error('Failed to parse Claude response:', error.message);
  // Fallback: use raw idea as enriched text
  return [{
    json: {
      ...ideaData,
      enrichedText: ideaData.rawIdea,
      napkinPrompt: `Create a ${ideaData.diagramType || 'flowchart'} diagram visualizing: ${ideaData.rawIdea.substring(0, 200)}`,
      keyNodes: [],
      relationships: [],
      alternativeFormats: [],
      contentAngles: [],
      estimatedComplexity: 'moderate',
      enrichedAt: new Date().toISOString(),
      stage: 'enriched-fallback',
      parseError: error.message
    }
  }];
}

// Assemble complete output package
const napkinAssets = $input.first().json;
const ideaData = $node['Parse Claude Enrichment'].first().json;
const jobData = $node['NapkinAI - Submit Idea for Visual'].first().json;

const outputPackage = {
  // Identity
  ideaId: ideaData.ideaId,
  title: ideaData.title,
  completedAt: new Date().toISOString(),
  processingTime: `${((new Date() - new Date(ideaData.requestedAt)) / 1000).toFixed(1)}s`,

  // Original input
  input: {
    rawIdea: ideaData.rawIdea,
    diagramTypeRequested: ideaData.diagramType,
    targetAudience: ideaData.targetAudience,
    visualStyle: ideaData.visualStyle
  },

  // AI Analysis
  analysis: {
    enrichedText: ideaData.enrichedText,
    diagramTypeSelected: ideaData.diagramType,
    keyNodes: ideaData.keyNodes,
    relationships: ideaData.relationships,
    estimatedComplexity: ideaData.estimatedComplexity,
    colorScheme: ideaData.colorScheme
  },

  // Generated visuals
  visuals: {
    jobId: jobData.jobId,
    mainDiagram: napkinAssets.assets?.find(a => a.type === 'primary') || napkinAssets.assets?.[0],
    allAssets: napkinAssets.assets || [],
    downloadUrls: (napkinAssets.assets || []).map(a => ({ format: a.format, url: a.downloadUrl, size: a.size })),
    thumbnailUrl: napkinAssets.thumbnailUrl || ''
  },

  // Content strategy
  contentStrategy: {
    alternativeFormats: ideaData.alternativeFormats,
    contentAngles: ideaData.contentAngles,
    napkinPrompt: ideaData.napkinPrompt
  },

  // Quick summary for notifications
  summary: {
    assetCount: (napkinAssets.assets || []).length,
    formats: (napkinAssets.assets || []).map(a => a.format),
    topAngle: ideaData.contentAngles?.[0]?.hook || 'Visual ready',
    bestFormat: ideaData.alternativeFormats?.[0]?.format || 'Diagram'
  }
};

return [{ json: outputPackage }];

