// Track completed visuals
const output = $input.item.json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.processedIdeas) {
  staticData.processedIdeas = {};
}

// Clean entries older than 90 days
const ninetyDaysAgo = Date.now() - (90 * 24 * 60 * 60 * 1000);
for (const key in staticData.processedIdeas) {
  if (staticData.processedIdeas[key].timestamp < ninetyDaysAgo) {
    delete staticData.processedIdeas[key];
  }
}

// Mark as processed
staticData.processedIdeas[output.ideaId] = {
  ideaId: output.ideaId,
  title: output.title,
  jobId: output.visuals?.jobId,
  assetCount: output.summary?.assetCount,
  completedAt: output.completedAt,
  timestamp: Date.now()
};

console.log(`✅ Marked complete: ${output.ideaId} - ${output.title}`);

return {
  json: {
    status: 'success',
    ideaId: output.ideaId,
    title: output.title,
    message: `Visual generation complete. ${output.summary?.assetCount || 0} assets delivered.`,
    assets: output.visuals?.downloadUrls || [],
    contentAngles: output.contentStrategy?.contentAngles || [],
    alternativeFormats: output.contentStrategy?.alternativeFormats || []
  }
};
